// Icon component helper - renders SVG icon with optional size and color
export const renderIcon = (iconName, className = '', size = 18) => {
  const icon = Icons[iconName];
  if (!icon) return null;
  // Replace size in SVG
  const sizedIcon = icon.replace(/width="\d+"/, `width="${size}"`).replace(/height="\d+"/, `height="${size}"`);
  return `<span class="${className}" style="display: inline-flex; align-items: center;">${sizedIcon}</span>`;
};

// Get file type icon class based on file type
export const getFileTypeIconClass = (fileType) => {
  const classMap = {
    'PDF': 'icon-pdf',
    'Word': 'icon-word',
    'Excel': 'icon-excel',
    'PowerPoint': 'icon-ppt',
    'Image': 'icon-image',
    'Text': 'icon-text',
    'Archive': 'icon-archive',
    'Folder': 'icon-folder',
  };
  return classMap[fileType] || 'icon-text';
};

// Get icon for file type (returns icon name)
export const getIconName = (item) => {
  if (item.type === 'folder') return 'folder';
  
  const iconMap = {
    'PDF': 'filePdf',
    'Word': 'fileWord',
    'Excel': 'fileExcel',
    'PowerPoint': 'filePpt',
    'Image': 'fileImage',
    'Text': 'fileText',
    'Archive': 'fileArchive',
  };
  
  return iconMap[item.fileType] || 'file';
};

// Get icon for file type (old function, kept for compatibility)
export const getIcon = (item) => {
  if (item.type === 'folder') return '📁';
  
  const iconMap = {
    'PDF': '📕',
    'Word': '📘',
    'Excel': '📗',
    'CSV': '📗',
    'PowerPoint': '📙',
    'Image': '🖼️',
    'Video': '🎞️',
    'Audio': '🎵',
    'Text': '📝'
  };
  
  return iconMap[item.fileType] || '📄';
};

// Get file type from extension
export const getFileType = (filename) => {
  const ext = filename.split('.').pop().toLowerCase();
  const typeMap = {
    'pdf': 'PDF',
    'doc': 'Word',
    'docx': 'Word',
    'xls': 'Excel',
    'xlsx': 'Excel',
    'csv': 'CSV',
    'ppt': 'PowerPoint',
    'pptx': 'PowerPoint',
    'jpg': 'Image',
    'jpeg': 'Image',
    'png': 'Image',
    'gif': 'Image',
    'mp4': 'Video',
    'webm': 'Video',
    'mov': 'Video',
    'avi': 'Video',
    'mkv': 'Video',
    'm4v': 'Video',
    'ogg': 'Video',
    'mp3': 'Audio',
    'wav': 'Audio',
    'flac': 'Audio',
    'aac': 'Audio',
    'm4a': 'Audio',
    'wma': 'Audio',
    'txt': 'Text',
    'md': 'Text',
    'zip': 'Archive',
    'rar': 'Archive',
    '7z': 'Archive',
  };
  return typeMap[ext] || 'Document';
};

// Generate unique ID
export const generateId = () => {
  return Date.now() + Math.floor(Math.random() * 1000);
};

// Get current date in YYYY-MM-DD format
export const getCurrentDate = () => {
  return new Date().toISOString().split('T')[0];
};

// Get current date time as string
export const getCurrentDateTime = () => {
  return new Date().toLocaleString();
};

// Check if file is text-based
export const isTextFile = (filename, mimeType) => {
  if (mimeType && mimeType.startsWith('text/')) return true;
  const textExtensions = ['txt', 'js', 'css', 'html', 'json', 'xml', 'csv', 'md', 'py', 'java', 'c', 'cpp', 'h', 'sql', 'log'];
  const ext = filename.split('.').pop().toLowerCase();
  return textExtensions.includes(ext);
};

// Escape HTML
export const escapeHtml = (text) => {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
};

// View titles mapping (without emojis for professional look)
